module RefModule(input [3:0] a, input [3:0] b, output reg [3:0] sum);// Changed sum to output reg
    wire [4:0] temp_sum;

      wire _n01 = a[0] ^ b[0];
  wire _c01 = a[0] & b[0];
  wire _n02 = a[1] ^ b[1] ^ _c01;
  wire _c02 = (a[1] & b[1]) | (a[1] & _c01) | (b[1] & _c01);
  wire _n03 = a[2] ^ b[2] ^ _c02;
  wire _c03 = (a[2] & b[2]) | (a[2] & _c02) | (b[2] & _c02);
  wire _n04 = a[3] ^ b[3] ^ _c03;
  wire _c04 = (a[3] & b[3]) | (a[3] & _c03) | (b[3] & _c03);
  assign temp_sum = {_n01, _n02, _n03, _n04};

    always @(*) begin
        if (temp_sum > 15) begin
            sum = temp_sum - 16; // sum can now be assigned
        end
        else begin
            sum = temp_sum; // sum can now be assigned
        end
    end
endmodule
